import{_ as a,o as i,c as s,ag as t}from"./chunks/framework.BGkQCay2.js";const u=JSON.parse('{"title":"VAPE: Vex Analyzer, Profiler & Visualizer Ecosystem","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tooling/vape.md","filePath":"guide/tooling/vape.md"}'),n={name:"guide/tooling/vape.md"};function r(l,e,o,c,h,p){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="vape-vex-analyzer-profiler-visualizer-ecosystem" tabindex="-1">VAPE: Vex Analyzer, Profiler &amp; Visualizer Ecosystem <a class="header-anchor" href="#vape-vex-analyzer-profiler-visualizer-ecosystem" aria-label="Permalink to &quot;VAPE: Vex Analyzer, Profiler &amp; Visualizer Ecosystem&quot;">​</a></h1><p>VAPE is a first-class static analysis and performance profiling ecosystem built directly into the Vex compiler. Unlike other languages where safety auditing, microarchitectural pipeline profiling, and compilation state visualization require complex third-party setups, Vex integrates these components natively under a single command interface.</p><hr><h2 id="🏛️-architecture-integration" tabindex="-1">🏛️ Architecture &amp; Integration <a class="header-anchor" href="#🏛️-architecture-integration" aria-label="Permalink to &quot;🏛️ Architecture &amp; Integration&quot;">​</a></h2><p>VAPE operates as an end-to-end telemetry pipeline inside the Vex compiler CLI, hooking directly into the AST parsing, HIR lowering, and LLVM CodeGen phases.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Source[Vex Source File] --&gt; CLI{vex CLI}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    CLI --&gt;|analyze| Linter[Static Linter]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    CLI --&gt;|view| Visualizer[CST/CFG/DFG Visualizer]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    CLI --&gt;|prof| Profiler[LLVM-MCA Pipeline Simulator]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Linter --&gt;|Warnings / Diagnostics| Console[Stdout / LSP / HTML Report]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Visualizer --&gt;|DOT / JSON| Graphviz[Graphviz DOT / JSON Exporters]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Profiler --&gt;|Port Latency / IPC| Dashboard[Terminal UI / HTML Dashboard]</span></span></code></pre></div><hr><h2 id="🔍-1-static-linter-vex-analyze" tabindex="-1">🔍 1. Static Linter (<code>vex analyze</code>) <a class="header-anchor" href="#🔍-1-static-linter-vex-analyze" aria-label="Permalink to &quot;🔍 1. Static Linter (\`vex analyze\`)&quot;">​</a></h2><p>The Vex linter runs as a post-lowering compiler pass over the High-Level Intermediate Representation (HIR) and parsed syntax trees. It guarantees code safety and hygiene before binary compilation.</p><h3 id="cli-usage" tabindex="-1">CLI Usage <a class="header-anchor" href="#cli-usage" aria-label="Permalink to &quot;CLI Usage&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Analyze a Vex file and output formatted terminal diagnostics</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> analyze</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Output diagnostics in raw JSON format for IDE/LSP integrations</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> analyze</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --format=json</span></span></code></pre></div><h3 id="active-lint-rules" tabindex="-1">Active Lint Rules <a class="header-anchor" href="#active-lint-rules" aria-label="Permalink to &quot;Active Lint Rules&quot;">​</a></h3><h4 id="rule-w0002-unused-imports" tabindex="-1">Rule <code>W0002</code>: Unused Imports <a class="header-anchor" href="#rule-w0002-unused-imports" aria-label="Permalink to &quot;Rule \`W0002\`: Unused Imports&quot;">​</a></h4><ul><li><strong>Description:</strong> Warns on imports that are declared in the module header but never referenced in statements.</li><li><strong>Wildcards:</strong> Correctly detects unused wildcard imports (e.g. <code>import * as alias from &quot;module&quot;</code>).</li><li><strong>Help Option:</strong> Helps keep dependencies clean, reducing compilation times.</li></ul><h4 id="rule-w0010-unsafe-ffi-boundary-safety" tabindex="-1">Rule <code>W0010</code>: Unsafe FFI Boundary Safety <a class="header-anchor" href="#rule-w0010-unsafe-ffi-boundary-safety" aria-label="Permalink to &quot;Rule \`W0010\`: Unsafe FFI Boundary Safety&quot;">​</a></h4><ul><li><strong>Description:</strong> Audits external FFI functions (<code>extern &quot;C&quot;</code>). Emits warnings if FFI calls are not guarded by the Vex inline rescue operator <code>!&gt;</code>.</li><li><strong>Why:</strong> FFI calls can trigger external crashes. Guarding them with rescue blocks (<code>ffi_call() !&gt; { recovery_block }</code>) ensures program resilience.</li></ul><h4 id="rule-w0011-redundant-literal-clones" tabindex="-1">Rule <code>W0011</code>: Redundant Literal Clones <a class="header-anchor" href="#rule-w0011-redundant-literal-clones" aria-label="Permalink to &quot;Rule \`W0011\`: Redundant Literal Clones&quot;">​</a></h4><ul><li><strong>Description:</strong> Highlights calls to <code>.clone()</code> or <code>.copy()</code> on literals (e.g. <code>100.clone()</code>).</li><li><strong>Help Option:</strong> Literals are copy-by-value, making duplicate allocation calls redundant.</li></ul><hr><h2 id="📊-2-intermediate-state-visualizer-vex-view" tabindex="-1">📊 2. Intermediate State Visualizer (<code>vex view</code>) <a class="header-anchor" href="#📊-2-intermediate-state-visualizer-vex-view" aria-label="Permalink to &quot;📊 2. Intermediate State Visualizer (\`vex view\`)&quot;">​</a></h2><p><code>vex view</code> allows developers to inspect intermediate compiler representations (AST, Control Flow, and SSA Data Flow) to debug performance problems or complex compiler transformations.</p><h3 id="cli-usage-1" tabindex="-1">CLI Usage <a class="header-anchor" href="#cli-usage-1" aria-label="Permalink to &quot;CLI Usage&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Export the parsed Rowan CST as text layout</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> view</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ast</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Export the parsed Rowan CST in structured JSON format</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> view</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ast</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --format=json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Export the Control Flow Graph (CFG) in Graphviz DOT format</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> view</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cfg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output=cfg.dot</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Export the Data Flow Graph (DFG) in Graphviz DOT format</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> view</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dfg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output=dfg.dot</span></span></code></pre></div><h3 id="exporters" tabindex="-1">Exporters <a class="header-anchor" href="#exporters" aria-label="Permalink to &quot;Exporters&quot;">​</a></h3><ol><li><strong>Rowan AST Exporter:</strong> Serializes the concrete syntax tree, showing tokens and structural syntax nodes.</li><li><strong>LLVM Control Flow Graph (CFG):</strong> Outputs basic block jump graphs showing branch target locations and instructions. Useful for analyzing branch predictions and execution hotpaths.</li><li><strong>LLVM Data Flow Graph (DFG):</strong> Maps Static Single Assignment (SSA) values and operand dependencies. Allows developers to trace register dependency chains.</li></ol><hr><h2 id="⚡-3-microarchitectural-profiler-vex-prof" tabindex="-1">⚡ 3. Microarchitectural Profiler (<code>vex prof</code>) <a class="header-anchor" href="#⚡-3-microarchitectural-profiler-vex-prof" aria-label="Permalink to &quot;⚡ 3. Microarchitectural Profiler (\`vex prof\`)&quot;">​</a></h2><p><code>vex prof</code> simulates instruction execution cycles on target CPU microarchitectures by compiling Vex source to assembly, injecting LLVM-MCA start/stop markers, and programmatically running the LLVM Machine Code Analyzer.</p><div class="tip custom-block"><p class="custom-block-title">Why Vex is Better Than Rust and Go</p><ul><li><strong>Rust:</strong> Requires manual generation of assembly files (<code>cargo rustc -- --emit=asm</code>), manual injection of <code># LLVM-MCA-BEGIN</code> markers, target machine architecture lookup, and external execution.</li><li><strong>Go:</strong> Lacks microarchitectural execution unit profiling.</li><li><strong>Vex:</strong> Accomplishes the entire sequence automatically via <code>vex prof main.vx</code>.</li></ul></div><h3 id="cli-usage-2" tabindex="-1">CLI Usage <a class="header-anchor" href="#cli-usage-2" aria-label="Permalink to &quot;CLI Usage&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Profile the code using the native host CPU architecture</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prof</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Profile simulating a specific target processor model (Intel/AMD/Apple Silicon)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prof</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cpu=apple-m2</span></span></code></pre></div><h3 id="metrics-highlighted" tabindex="-1">Metrics Highlighted <a class="header-anchor" href="#metrics-highlighted" aria-label="Permalink to &quot;Metrics Highlighted&quot;">​</a></h3><ul><li><strong>Total Cycles:</strong> The total execution clock cycles simulated by LLVM-MCA.</li><li><strong>IPC (Instructions Per Cycle):</strong> Throughput rating representing hardware pipeline utilization.</li><li><strong>Block RThroughput (Reciprocal Throughput):</strong> Estimated cycles required to execute one iteration of a loop block.</li><li><strong>Resource Pressure Heatmaps:</strong> Shows pipeline pressure across execution unit ports (e.g. arithmetic vs memory units).</li><li><strong>Active Pipeline Stalls:</strong> Detects which hardware stages are limiting dispatch (e.g. Retire Control Unit token starvation, scheduler queue full).</li><li><strong>Dependency Bottlenecks:</strong> Details registers/execution units responsible for critical paths (e.g. register dependencies, resource interference).</li></ul><div class="info custom-block"><p class="custom-block-title">Cross-Platform Execution</p><p>Standard <code>llvm-mca</code> assembly parsers crash on macOS due to Darwin-specific assembler directives (like <code>.subsections_via_symbols</code>). Vex works around this automatically by filtering out non-instruction dot-directives (preserving local <code>.L</code> branch labels) at runtime.</p></div><hr><h2 id="📈-4-next-generation-html-performance-reports" tabindex="-1">📈 4. Next Generation: HTML Performance Reports <a class="header-anchor" href="#📈-4-next-generation-html-performance-reports" aria-label="Permalink to &quot;📈 4. Next Generation: HTML Performance Reports&quot;">​</a></h2><p>VAPE is being updated to support <code>--report=html</code>. This merges static lints, control flow visualizers, and simulated execution timelines into an interactive, visual dashboard:</p><ul><li><strong>Interactive CFG/DFG Graph:</strong> Renders code blocks visually using custom canvas or SVG elements.</li><li><strong>Color-Coded Latency:</strong> Highlights hot instructions with cycle density heatmaps.</li><li><strong>Inline Tooltips:</strong> Shows execution delays and register hazards directly inside source file views.</li></ul><hr><h2 id="🚀-5-advanced-analyzer-roadmap-future-plans" tabindex="-1">🚀 5. Advanced Analyzer Roadmap (Future Plans) <a class="header-anchor" href="#🚀-5-advanced-analyzer-roadmap-future-plans" aria-label="Permalink to &quot;🚀 5. Advanced Analyzer Roadmap (Future Plans)&quot;">​</a></h2><p>To push VAPE beyond standard tooling available in Go and Rust, the following advanced features are planned for future development:</p><h3 id="_1-memory-layout-cache-line-visualizer" tabindex="-1">1. Memory Layout &amp; Cache-Line Visualizer <a class="header-anchor" href="#_1-memory-layout-cache-line-visualizer" aria-label="Permalink to &quot;1. Memory Layout &amp; Cache-Line Visualizer&quot;">​</a></h3><ul><li><strong>Goal:</strong> Visually map how struct fields are laid out in memory, identifying padding waste and cache-line boundaries.</li><li><strong>Benefit:</strong> Enables developers to reorder struct fields to fit perfectly within L1 cache lines (e.g., 64 bytes) without relying on external macros or guesswork.</li></ul><h3 id="_2-auto-remediation-quick-fixes" tabindex="-1">2. Auto-Remediation &amp; Quick-Fixes <a class="header-anchor" href="#_2-auto-remediation-quick-fixes" aria-label="Permalink to &quot;2. Auto-Remediation &amp; Quick-Fixes&quot;">​</a></h3><ul><li><strong>Goal:</strong> Provide automated, semantic code refactoring directly from the CLI (<code>vex fix</code>) or via LSP code actions.</li><li><strong>Benefit:</strong> Not just identifying redundant <code>.clone()</code> calls or borrowing issues, but actually writing the correct borrow-semantics fix directly into the source file.</li></ul><h3 id="_3-escape-analysis-visualizer" tabindex="-1">3. Escape Analysis Visualizer <a class="header-anchor" href="#_3-escape-analysis-visualizer" aria-label="Permalink to &quot;3. Escape Analysis Visualizer&quot;">​</a></h3><ul><li><strong>Goal:</strong> Map variables that escape to the heap (allocations) directly onto the Data Flow Graph.</li><li><strong>Benefit:</strong> Turns raw escape analysis text (like Go&#39;s <code>-m</code>) into an intuitive graph, showing exactly <em>which</em> function call forced a variable onto the heap.</li></ul><h3 id="_4-simd-vectorization-predictor" tabindex="-1">4. SIMD &amp; Vectorization Predictor <a class="header-anchor" href="#_4-simd-vectorization-predictor" aria-label="Permalink to &quot;4. SIMD &amp; Vectorization Predictor&quot;">​</a></h3><ul><li><strong>Goal:</strong> Statically analyze loops and provide human-readable feedback on why a loop cannot be vectorized.</li><li><strong>Benefit:</strong> Explicitly highlights loop-carried dependencies, guiding developers on how to restructure code for SIMD acceleration.</li></ul><h3 id="_5-non-contiguous-memory-access-warning" tabindex="-1">5. Non-Contiguous Memory Access Warning <a class="header-anchor" href="#_5-non-contiguous-memory-access-warning" aria-label="Permalink to &quot;5. Non-Contiguous Memory Access Warning&quot;">​</a></h3><ul><li><strong>Goal:</strong> Detect sub-optimal array/matrix traversals (e.g., column-major reads on row-major data).</li><li><strong>Benefit:</strong> Prevents massive performance drops caused by cache-thrashing, a common pitfall in performance-critical applications.</li></ul><h3 id="_6-branch-predictability-pgo-hints" tabindex="-1">6. Branch Predictability &amp; PGO Hints <a class="header-anchor" href="#_6-branch-predictability-pgo-hints" aria-label="Permalink to &quot;6. Branch Predictability &amp; PGO Hints&quot;">​</a></h3><ul><li><strong>Goal:</strong> Analyze <code>if/else</code> control flow graphs to predict branch-predictor friendliness.</li><li><strong>Benefit:</strong> Suggests replacing highly unpredictable branches with branchless alternatives (e.g., lookup tables or conditional moves) for better pipeline throughput.</li></ul>`,53)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
